function translateRuntimeText(sourceText, language) {
  const lang = normalizeUiLanguage(language);
  const text = String(sourceText ?? "");
  if (!text || !text.trim() || lang === "en") return text;
  const fromCore = UI_TEXT[lang]?.[text];
  if (fromCore) return fromCore;
  const fromRuntime = UI_RUNTIME_TEXT[lang]?.[text];
  if (fromRuntime) return fromRuntime;
  const terms = Object.entries(UI_RUNTIME_TERMS[lang] || {}).sort((a, b) => b[0].length - a[0].length);
  let out = text;
  for (const [enPart, localizedPart] of terms) out = out.split(enPart).join(localizedPart);
  return out;
}

function toEnglishFromKnownLocalization(value) {
  const text = String(value ?? "");
  if (!text) return text;

  const localeMaps = ["es", "ja"];
  for (const locale of localeMaps) {
    const sources = [UI_TEXT[locale] || {}, UI_RUNTIME_TEXT[locale] || {}];
    for (const src of sources) {
      for (const [enText, localizedText] of Object.entries(src)) {
        if (localizedText === text) return enText;
      }
    }
  }

  let out = text;
  for (const locale of localeMaps) {
    const reverseTerms = Object.entries(UI_RUNTIME_TERMS[locale] || {})
      .sort((a, b) => b[1].length - a[1].length);
    for (const [enPart, localizedPart] of reverseTerms) {
      out = out.split(localizedPart).join(enPart);
    }
  }
  return out;
}

function normalizeUiLanguage(raw) {
  const value = String(raw || "").trim().toLowerCase();
  return SUPPORTED_UI_LANGUAGES.includes(value) ? value : "en";
}

function loadUiLanguagePreference() {
  if (typeof window === "undefined") return "en";
  try {
    return normalizeUiLanguage(window.localStorage.getItem(LS_UI_LANG_KEY));
  } catch {
    return "en";
  }
}

function normalizeBillingCycle(raw) {
  const value = String(raw || "").trim().toLowerCase();
  return value === "yearly" ? "yearly" : "monthly";
}

function isValidFlowSignupEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(email || "").trim());
}

function normalizeConversionSignupState(rawState) {
  const raw = rawState && typeof rawState === "object" ? rawState : {};
  return {
    signupCompletedForFlow: Boolean(raw.signupCompletedForFlow),
    flowEmail: String(raw.flowEmail || "").trim(),
    flowPassword: String(raw.flowPassword || ""),
    selectedPlan: normalizePlanId(raw.selectedPlan),
    selectedBillingCycle: normalizeBillingCycle(raw.selectedBillingCycle),
    updatedAt: Number.isFinite(raw.updatedAt) ? Number(raw.updatedAt) : Date.now(),
  };
}

function hasReusableConversionSignupState(rawState) {
  const state = normalizeConversionSignupState(rawState);
  if (!state.signupCompletedForFlow) return false;
  if (!isValidFlowSignupEmail(state.flowEmail)) return false;
  if (String(state.flowPassword || "").length < 8) return false;
  return true;
}

function loadConversionSignupState() {
  if (typeof window === "undefined") return normalizeConversionSignupState(null);
  try {
    const parsed = JSON.parse(window.sessionStorage.getItem(SESSION_CONVERSION_SIGNUP_KEY) || "null");
    return normalizeConversionSignupState(parsed);
  } catch {
    return normalizeConversionSignupState(null);
  }
}

function persistConversionSignupState(nextState) {
  if (typeof window === "undefined") return;
  try {
    window.sessionStorage.setItem(SESSION_CONVERSION_SIGNUP_KEY, JSON.stringify(normalizeConversionSignupState(nextState)));
  } catch {}
}

function clearConversionSignupState() {
  if (typeof window === "undefined") return;
  try {
    window.sessionStorage.removeItem(SESSION_CONVERSION_SIGNUP_KEY);
  } catch {}
}

function normalizeProfileData(rawProfile) {
  const profile = rawProfile && typeof rawProfile === "object" ? rawProfile : {};
  const favoriteInstrumentIds = Array.isArray(profile.favoriteInstrumentIds)
    ? profile.favoriteInstrumentIds.map((id) => String(id || "")).filter(Boolean)
    : [];
  return {
    avatarDataUrl: String(profile.avatarDataUrl || ""),
    displayName: String(profile.displayName || ""),
    favoriteInstrumentIds,
    heardAbout: String(profile.heardAbout || ""),
    gender: String(profile.gender || ""),
    birthday: String(profile.birthday || ""),
  };
}

function isProfileSetupComplete(rawProfile) {
  const profile = normalizeProfileData(rawProfile);
  const hasDisplayName = String(profile.displayName || "").trim().length > 0;
  const hasGender = String(profile.gender || "").trim().length > 0;
  const hasBirthday = String(profile.birthday || "").trim().length > 0;
  const hasFavoriteInstrument = Array.isArray(profile.favoriteInstrumentIds) && profile.favoriteInstrumentIds.length > 0;
  const hasDiscoverySource = String(profile.heardAbout || "").trim().length > 0;
  return hasDisplayName && hasGender && hasBirthday && hasFavoriteInstrument && hasDiscoverySource;
}

function normalizeUserState(rawState) {
  const base = {
    isLoggedIn: false,
    hasMembership: false,
    everHadMembership: false,
    planType: null,
    email: "",
    profile: normalizeProfileData(null),
  };
  if (!rawState || typeof rawState !== "object") return base;
  const plan =
    rawState.planType === "solo" || rawState.planType === "band" || rawState.planType === "creator"
      ? rawState.planType
      : null;
  const hasMembership = Boolean(rawState.hasMembership);
  const everHadMembership = Boolean(rawState.everHadMembership || hasMembership || plan);
  return {
    isLoggedIn: Boolean(rawState.isLoggedIn),
    hasMembership,
    everHadMembership,
    planType: plan,
    email: String(rawState.email || ""),
    profile: normalizeProfileData(rawState.profile),
  };
}

function loadUserStateFromStorage() {
  if (typeof window === "undefined") return normalizeUserState(null);
  try {
    const parsed = JSON.parse(window.localStorage.getItem(LS_USER_STATE_KEY) || "null");
    return normalizeUserState(parsed);
  } catch {
    return normalizeUserState(null);
  }
}

function persistUserStateToStorage(nextState) {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(LS_USER_STATE_KEY, JSON.stringify(normalizeUserState(nextState)));
  } catch {}
}

function normalizePlanId(planId) {
  const raw = String(planId || "").trim().toLowerCase();
  if (raw === "band") return "band";
  if (raw === "creator") return "creator";
  return "solo";
}

const MEMBERSHIP_PRICING_SOURCE = Object.freeze({
  solo: Object.freeze({ monthly: 3.99 }),
  band: Object.freeze({ monthly: 6.99 }),
  creator: Object.freeze({ monthly: 9.99 }),
});

function getPlanPricing(planId) {
  const normalized = normalizePlanId(planId);
  const monthly = Number(MEMBERSHIP_PRICING_SOURCE[normalized]?.monthly ?? MEMBERSHIP_PRICING_SOURCE.solo.monthly);
  const yearlyOriginal = Number((monthly * 12).toFixed(2));
  const yearlyDiscounted = Number((yearlyOriginal * 0.8).toFixed(2));
  return {
    monthly,
    yearlyOriginal,
    yearlyDiscounted,
  };
}

function formatUsdPriceWithPeriod(amount, period) {
  return `$${Number(amount || 0).toFixed(2)} / ${period}`;
}

function getPlanMeta(planId) {
  const normalized = normalizePlanId(planId);
  const pricing = getPlanPricing(normalized);
  if (normalized === "creator") {
    return {
      id: "creator",
      label: "Creator Plan",
      monthly: formatUsdPriceWithPeriod(pricing.monthly, "month"),
      yearly: formatUsdPriceWithPeriod(pricing.yearlyDiscounted, "year"),
    };
  }
  if (normalized === "band") {
    return {
      id: "band",
      label: "Band Plan",
      monthly: formatUsdPriceWithPeriod(pricing.monthly, "month"),
      yearly: formatUsdPriceWithPeriod(pricing.yearlyDiscounted, "year"),
    };
  }
  return {
    id: "solo",
    label: "Solo Plan",
    monthly: formatUsdPriceWithPeriod(pricing.monthly, "month"),
    yearly: formatUsdPriceWithPeriod(pricing.yearlyDiscounted, "year"),
  };
}

function getPlanPermissions(planType) {
  const normalized = normalizePlanId(planType);
  if (normalized === "creator") {
    return {
      canSave: true,
      canExportPdf: true,
      canExportPng: true,
      canUseTapToSync: true,
      canUseSetlistCreator: true,
      maxSavedTabs: Infinity,
    };
  }
  if (normalized === "band") {
    return {
      canSave: true,
      canExportPdf: true,
      canExportPng: false,
      canUseTapToSync: false,
      canUseSetlistCreator: true,
      maxSavedTabs: 250,
    };
  }
  return {
    canSave: true,
    canExportPdf: false,
    canExportPng: false,
    canUseTapToSync: false,
    canUseSetlistCreator: false,
    maxSavedTabs: 50,
  };
}

