            <ul style={{ margin: 0, paddingLeft: 18, display: "grid", gap: 6 }}>
              <li>Full desktop editor</li>
              <li>Project library</li>
              <li>Unlimited exports</li>
              <li>Dark mode</li>
            </ul>
            <button
              type="button"
              onClick={showDesktopNotice}
