                    lineHeight: 1.2,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    cursor: "pointer",
                    borderColor: tuningOpen ? THEME.accent : THEME.border,
                    boxShadow: tuningOpen ? `0 0 0 3px ${withAlpha(THEME.accent, 0.16)}` : "none",
                    gap: 10,
